output.sparql:
SELECT DISTINCT ?songLabel WHERE {
  ?song wdt:P175 wd:Q313578 .
  ?song rdfs:label ?songLabel .
  FILTER (lang(?songLabel) = "en")
  FILTER (STRBEFORE(STR(?songLabel), " (")) = "Ice Ice Baby")
}

